/* ---------- shared reveal-on-scroll hook ---------- */
function useReveal() {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const prefersReduced = window.matchMedia(
      "(prefers-reduced-motion: reduce)"
    ).matches;
    if (prefersReduced) {
      setVisible(true);
      return;
    }
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setVisible(true);
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.15 }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, []);

  return [ref, visible];
}

/* ---------- cursor (carried over from Home) ---------- */
function CursorDot() {
  const cursorRef = useRef(null);
  useEffect(() => {
    const cursor = cursorRef.current;
    if (!cursor) return;
    const onMove = (e) => {
      cursor.style.left = e.clientX + "px";
      cursor.style.top = e.clientY + "px";
    };
    document.addEventListener("mousemove", onMove);
    const interactiveEls = document.querySelectorAll(
      "a, button, .proj-card, .filmstrip-container"
    );
    const onEnter = () => cursor.classList.add("hover");
    const onLeave = () => cursor.classList.remove("hover");
    interactiveEls.forEach((el) => {
      el.addEventListener("mouseenter", onEnter);
      el.addEventListener("mouseleave", onLeave);
    });
    return () => {
      document.removeEventListener("mousemove", onMove);
      interactiveEls.forEach((el) => {
        el.removeEventListener("mouseenter", onEnter);
        el.removeEventListener("mouseleave", onLeave);
      });
    };
  }, []);
  return <div className="cursor" id="cursor" ref={cursorRef} aria-hidden="true" />;
}

/* ---------- FilmStrip: drag-to-scroll, physics-based ---------- */
const RESISTANCE = 0.35;
const FRICTION = 0.94;
const MIN_VELOCITY = 0.05;

function FilmStrip({ images }) {
  const containerRef = useRef(null);
  const trackRef = useRef(null);
  const [activeDot, setActiveDot] = useState(0);

  const state = useRef({
    offset: 0,
    dragging: false,
    startX: 0,
    startOffset: 0,
    lastX: 0,
    lastT: 0,
    velocity: 0,
    minOffset: 0,
    rafId: 0,
  });

  const clamp = useCallback((value, min, max) => {
    if (value > max) return max + (value - max) * RESISTANCE;
    if (value < min) return min + (value - min) * RESISTANCE;
    return value;
  }, []);

  const applyTransform = useCallback((x) => {
    if (trackRef.current) {
      trackRef.current.style.transform = `translate3d(${x}px, 0, 0)`;
    }
    const s = state.current;
    if (s.minOffset < 0) {
      const progress = Math.min(1, Math.max(0, -x / -s.minOffset));
      setActiveDot(Math.round(progress * 2));
    }
  }, []);

  const measure = useCallback(() => {
    if (!containerRef.current || !trackRef.current) return;
    const containerWidth = containerRef.current.offsetWidth;
    const trackWidth = trackRef.current.scrollWidth;
    state.current.minOffset = Math.min(0, containerWidth - trackWidth);
  }, []);

  useEffect(() => {
    measure();
    window.addEventListener("resize", measure);
    return () => window.removeEventListener("resize", measure);
  }, [measure]);

  const stopMomentum = () => {
    if (state.current.rafId) {
      cancelAnimationFrame(state.current.rafId);
      state.current.rafId = 0;
    }
  };

  const settle = useCallback(() => {
    const s = state.current;
    const step = () => {
      s.velocity *= FRICTION;
      s.offset += s.velocity;

      if (s.offset > 0) {
        s.offset += (0 - s.offset) * 0.18;
        s.velocity *= 0.7;
      } else if (s.offset < s.minOffset) {
        s.offset += (s.minOffset - s.offset) * 0.18;
        s.velocity *= 0.7;
      }

      applyTransform(s.offset);

      const settled =
        Math.abs(s.velocity) <= MIN_VELOCITY &&
        s.offset <= 0.5 &&
        s.offset >= s.minOffset - 0.5;

      if (!settled) {
        s.rafId = requestAnimationFrame(step);
      } else {
        s.offset = Math.max(s.minOffset, Math.min(0, s.offset));
        applyTransform(s.offset);
        s.rafId = 0;
      }
    };
    stopMomentum();
    s.rafId = requestAnimationFrame(step);
  }, [applyTransform]);

  const onPointerDown = (e) => {
    const s = state.current;
    stopMomentum();
    measure();
    s.dragging = true;
    s.startX = e.clientX;
    s.startOffset = s.offset;
    s.lastX = e.clientX;
    s.lastT = performance.now();
    s.velocity = 0;
    e.target.setPointerCapture && e.target.setPointerCapture(e.pointerId);
  };

  const onPointerMove = (e) => {
    const s = state.current;
    if (!s.dragging) return;
    const delta = e.clientX - s.startX;
    const raw = s.startOffset + delta;
    s.offset = clamp(raw, s.minOffset, 0);
    applyTransform(s.offset);

    const now = performance.now();
    const dt = now - s.lastT;
    if (dt > 0) {
      s.velocity = ((e.clientX - s.lastX) / dt) * 16.7;
    }
    s.lastX = e.clientX;
    s.lastT = now;
  };

  const endDrag = () => {
    const s = state.current;
    if (!s.dragging) return;
    s.dragging = false;
    settle();
  };

  return (
    <div className="filmstrip-outer">
      <div className="sprocket-row" aria-hidden="true" />
      <div
        ref={containerRef}
        className="filmstrip-container"
        onPointerDown={onPointerDown}
        onPointerMove={onPointerMove}
        onPointerUp={endDrag}
        onPointerCancel={endDrag}
        onPointerLeave={endDrag}
        role="group"
        aria-label="Photo film strip. Click and drag, or swipe, to browse."
        tabIndex={0}
      >
        <div ref={trackRef} className="filmstrip-track">
          {images.map((photo, i) => (
            <div className="filmstrip-frame" key={i}>
              <img
                src={photo.src}
                alt=""
                draggable={false}
                style={{
                  objectFit: photo.fit || "cover",
                  objectPosition: photo.position || "center",
                }}
              />
            </div>
          ))}
        </div>
      </div>
      <div className="sprocket-row" aria-hidden="true" />
    </div>
  );
}

