/* ---------- section: Beyond Design (text + icons + spotlight links) ---------- */
/* Click-and-drag decorative icon — freely repositionable within the section. */
function DraggableIcon({ src, alt, className, rotate = 0 }) {
  const [pos, setPos] = useState({ x: 0, y: 0 });
  const drag = useRef({ active: false, startX: 0, startY: 0, origX: 0, origY: 0 });
  const elRef = useRef(null);

  const onPointerDown = (e) => {
    drag.current = {
      active: true,
      startX: e.clientX,
      startY: e.clientY,
      origX: pos.x,
      origY: pos.y,
    };
    e.currentTarget.setPointerCapture(e.pointerId);
  };

  const onPointerMove = (e) => {
    if (!drag.current.active) return;
    const dx = e.clientX - drag.current.startX;
    const dy = e.clientY - drag.current.startY;
    setPos({ x: drag.current.origX + dx, y: drag.current.origY + dy });
  };

  const onPointerUp = (e) => {
    drag.current.active = false;
    try {
      e.currentTarget.releasePointerCapture(e.pointerId);
    } catch (err) {
      /* no-op */
    }
  };

  return (
    <img
      ref={elRef}
      src={src}
      alt={alt}
      aria-hidden={alt ? undefined : "true"}
      className={className + " draggable-icon"}
      style={{ transform: `translate(${pos.x}px, ${pos.y}px) rotate(${rotate}deg)` }}
      draggable={false}
      onPointerDown={onPointerDown}
      onPointerMove={onPointerMove}
      onPointerUp={onPointerUp}
      onPointerCancel={onPointerUp}
    />
  );
}

